  'foshan/lion': ('Barongsai', 'Sebagai ibu kota barongsai selatan, pertunjukan singa yang penuh warna ini sering kali menampilkan atraksi melompat di atas tiang.'),
  'foshan/ceramic': ('Keramik Shiwan', 'Tungku pembakaran berusia seribu tahun hingga kini masih memproduksi figurin keramik Shiwan yang ekspresif.'),
  'foshan/opera': ('Opera Kanton', 'Seni panggung yang paling digemari di Tiongkok selatan ini berkembang pesat di wilayah ini.'),
  'guiyang/pavilion': ('Paviliun Jiaxiu', 'Paviliun tiga tingkat yang terletak di Sungai Nanming ini telah menjadi ikon kota selama 400 tahun.'),
  'guiyang/sourfish': ('Sup Ikan Asam', 'Ikan yang dimasak dalam kaldu tomat fermentasi yang segar merupakan hidangan khas dari Guizhou.'),
  'guiyang/waterfall': ('Air Terjun Huangguoshu', 'Salah satu air terjun terbesar di Asia ini mengalir deras dan sering kali memancarkan pelangi di sekitarnya.'),
  'guiyang/miao': ('Budaya Miao', 'Festival dan kerajinan sulaman masyarakat Miao yang mengenakan mahkota perak menghidupkan suasana desa-desa pegunungan.'),
  'changchun/film': ('Kota Film', 'Studio tempat lahirnya sinema Tiongkok berdiri di sini, menjadikannya sebagai \'Hollywood dari Timur\'.'),
  'changchun/car': ('Kota Otomotif', 'Mobil pertama buatan dalam negeri Tiongkok diproduksi di pabrik-pabrik kota ini, menjadikannya ibu kota otomotif nasional.'),
  'changchun/palace': ('Istana Boneka', 'Istana tempat kaisar terakhir Tiongkok pernah tinggal ini menjadi saksi bisu sejarah yang penuh gejolak.'),
  'changchun/snow': ('Salju Musim Dingin', 'Selama musim dingin yang panjang, kota ini berkilau berhiaskan pahatan es dan arena ski.'),
  'xining/lake': ('Danau Qinghai', 'Danau air asin terbesar di Tiongkok ini terkenal dengan hamparan bunga kanola kuning yang mengelilinginya saat musim panas.'),
  'xining/monastery': ('Biara Kumbum', 'Salah satu dari enam biara besar Buddhisme Tibet ini tersohor karena seni pahatan mentega yak-nya.'),
  'xining/flower': ('Bunga Kanola', 'Pada bulan Juli, dataran tinggi ini diselimuti hamparan bunga kanola keemasan hingga ke cakrawala.'),
  'xining/lamb': ('Daging Yak dan Domba', 'Mi tarik dan sate domba khas kuliner Hui dan Tibet menjadi cita rasa utama di dataran tinggi ini.'),
  'guilin/karst': ('Karst Sungai Li', 'Puncak-puncak batu kapur yang menyembul dari kabut merupakan pemandangan yang tertera pada uang kertas 20 yuan.'),
  'guilin/elephant': ('Bukit Belalai Gajah', 'Bebatuan berbentuk gajah yang sedang mencelupkan belalainya ke sungai ini merupakan lambang kebanggaan kota.'),
  'guilin/terrace': ('Terasering Sawah Longji', 'Terasering \'Punggung Naga\' yang melingkari lereng bukit ini merupakan mahakarya dari kerja keras selama berabad-abad.'),
  'guilin/osmanthus': ('Bunga Osmanthus', 'Nama kota ini berarti \'hutan osmanthus\', dan saat musim gugur, kota ini dipenuhi aroma manis bunga tersebut.'),
  'wenzhou/merchant': ('Semangat Pedagang', 'Sering dijuluki sebagai \'Yahudi Tiongkok\', para pengusaha Wenzhou membangun jaringan bisnis di seluruh dunia.'),
  'wenzhou/shoe': ('Sepatu dan Kulit', 'Sebagian besar produksi sepatu kulit dunia berasal dari kota industri ini.'),
  'wenzhou/mountain': ('Pegunungan Yandang', 'Terkenal dengan air terjun dan puncak-puncak yang tajam, pegunungan ini dijuluki sebagai \'gunung pertama di tepi laut\'.'),
  'wenzhou/seafood': ('Hidangan Laut', 'Cumi-cumi, kerang, dan ikan dari Laut Tiongkok Timur menjadi bahan utama dalam hidangan lokal.'),
  'tangshan/memorial': ('Monumen Gempa Bumi', 'Taman peringatan untuk gempa besar tahun 1976 ini menjadi simbol kebangkitan kota yang terlahir kembali.'),
  'tangshan/coal': ('Tambang Batu Bara dan Baja', 'Tambang batu bara dan jalur kereta api modern pertama di Tiongkok dibuka di sini sebagai pusat industri awal.'),
  'tangshan/ceramic': ('Keramik Tangshan', 'Dikenal sebagai kota porselen di utara, keramik tulang dari Tangshan menghiasi meja makan dengan keanggunan.'),
  'tangshan/lake': ('Taman Nanhu', 'Taman danau yang dibangun di atas bekas lubang tambang ini kini berfungsi sebagai paru-paru hijau kota.'),
  'anshan/steel': ('Kota Baja', 'Pabrik baja terbesar di Tiongkok didirikan di sini, menjadikan kota ini sebagai ibu kota baja nasional.'),
  'anshan/jade': ('Giok Xiuyan', 'Kota ini merupakan pusat giok Tiongkok dan menjadi tempat bagi ukiran giok terbesar di dunia.'),
  'anshan/mountain': ('Gunung Qian', 'Dikenal sebagai Puncak Seribu Teratai, gunung ini merupakan puncak suci di wilayah utara yang dipenuhi kuil dan tebing.'),
  'anshan/spring': ('Pemandian Air Panas Tanggangzi', 'Pemandian air panas yang telah digunakan selama seribu tahun untuk pengobatan ini dulunya juga dikunjungi oleh para kaisar.'),
  'linyi/market': ('Pasar Grosir', 'Pusat grosir terbesar di Tiongkok Utara ini mendistribusikan berbagai macam barang ke seluruh penjuru negeri.'),
  'linyi/brush': ('Master Kaligrafi', 'Linyi adalah tempat kelahiran Wang Xizhi, sang maestro kaligrafi Tiongkok, sehingga kota ini dijuluki sebagai tanah tinta.'),
  'linyi/mountain': ('Gunung Meng', 'Gunung tertinggi kedua di Shandong ini merupakan kawasan udara bersih yang kaya akan oksigen dan air terjun.'),
  'linyi/pancake': ('Pancake Yimeng', 'Pancake jagung tipis yang dikenal sebagai jianbing ini merupakan makanan pokok tradisional masyarakat pegunungan Yimeng.'),
  'cangzhou/lion': ('Singa Besi', 'Patung singa dari besi cor raksasa yang berusia 1.100 tahun ini menjadi simbol kebanggaan kota Cangzhou.'),
  'cangzhou/martial': ('Seni Bela Diri', 'Dikenal sebagai rumah wushu di Tiongkok, kota ini melahirkan banyak master bela diri dan perguruan silat ternama.'),
  'cangzhou/canal': ('Kanal Besar', 'Kanal Besar Beijing-Hangzhou melintasi kota ini, di mana dermaga-dermaga kuno masih berdiri hingga saat ini.'),
  'cangzhou/jujube': ('Kurma Emas', 'Kurma \'benang emas\' yang manis dengan kulit tipis ini dianggap sebagai raja dari segala buah kering.'),
  'nantong/textile': ('Kota Tekstil', 'Sebagai pusat tekstil rumah tangga di Tiongkok, produk kain katun dari kota ini telah dipasarkan ke seluruh dunia.'),
  'nantong/mountain': ('Gunung Lang', 'Terletak di muara Sungai Yangtze, bukit suci dengan lima puncak ini menjadi destinasi ziarah sekaligus tempat untuk menikmati pemandangan.'),
  'nantong/kite': ('Layang-layang Bersiul', 'Layang-layang banyao yang dilengkapi peluit sehingga mengeluarkan suara dengungan merupakan kerajinan tradisional khas kota ini.'),
  'nantong/school': ('Pelopor Pendidikan', 'Industrialis Zhang Jian mendirikan sekolah modern dan museum pertama di Tiongkok di kota ini.'),
  'taizhou/opera': ('Mei Lanfang', 'Kota ini merupakan kampung halaman dari Mei Lanfang, maestro legendaris opera Peking.'),
  'taizhou/tea': ('Teh Pagi', 'Tradisi sarapan zaocha yang terdiri dari bakpao kukus dan teh seduh telah menjadi ritual masyarakat setempat.'),
  'taizhou/boat': ('Festival Perahu Qintong', 'Festival yang melibatkan ratusan pendayung ini menghidupkan suasana sungai saat musim semi tiba.'),
  'taizhou/meatball': ('Bakso Kepala Singa', 'Bakso babi berukuran besar dengan tekstur lembut ini merupakan hidangan klasik dari kuliner Huaiyang.'),
  'jinhua/ham': ('Ham Jinhua', 'Dibuat dengan metode pengawetan selama berabad-abad, ham berwarna merah ini merupakan yang paling terkenal di Tiongkok.'),
  'jinhua/film': ('Studio Hengdian', 'Sebagai lokasi syuting luar ruangan terbesar di dunia, tempat ini menjadi latar bagi banyak drama sejarah Tiongkok.'),
  'jinhua/cave': ('Gua Shuanglong', 'Gua bawah tanah yang dimasuki dengan perahu melalui celah batu rendah ini menawarkan pemandangan yang memukau.'),
  'jinhua/bridge': ('Jembatan Kuno', 'Jembatan batu melengkung dan kota air di sini memancarkan keanggunan khas wilayah Jiangnan.'),
  'wuhu/park': ('Fangte Wonderland', 'Salah satu taman hiburan terbesar di Tiongkok ini menawarkan pengalaman rekreasi yang seru bagi seluruh keluarga.'),
  'wuhu/ironart': ('Lukisan Besi', 'Lukisan besi yang elegan dan ditempa dari besi tempa merupakan kerajinan tangan yang telah berusia 300 tahun.'),
  'wuhu/rice': ('Pelabuhan Beras', 'Kota yang terletak di tepi Sungai Yangtze ini secara historis merupakan pasar beras terbesar di Tiongkok.'),
  'wuhu/river': ('Pelabuhan Yangtze', 'Pelabuhan sungai yang sibuk ini menjadikan kota tersebut sebagai gerbang laut bagi Provinsi Anhui.'),
  'huangshan/peak': ('Gunung Huangshan', 'Dengan puncak granit, lautan awan, dan pohon pinus yang unik, gunung ini merupakan gunung paling terkenal di Tiongkok.'),
  'huangshan/village': ('Desa Hongcun', 'Desa bergaya Hui yang dikelilingi kanal air dengan dinding putih ini terdaftar dalam situs warisan dunia UNESCO dan tampak seperti lukisan hidup.'),
  'huangshan/tea': ('Teh Maofeng', 'Teh hijau berujung halus yang dipetik di lereng berkabut ini merupakan salah satu dari sepuluh teh paling terkenal di Tiongkok.'),
  'huangshan/ink': ('Seni Tinta Huizhou', 'Tinta Hui, rumah kayu berukir, dan kaligrafi merupakan harta karun budaya yang tak ternilai dari wilayah ini.'),
  'yichun/moon': ('Gunung Mingyue', 'Gunung \'Bulan Terang\' ini terkenal dengan pemandian air panas dan pemandangan indah yang dapat dinikmati melalui kereta gantung.'),
  'yichun/spring': ('Pemandian Air Panas', 'Kandungan selenium yang langka dalam air panas alaminya menjadikan kota ini pusat wisata spa di Tiongkok.'),
  'yichun/zen': ('Buddhisme Chan', 'Kuil-kuil di pegunungan yang berakar pada sekte Chan Tiongkok mengajak pengunjung untuk menemukan ketenangan batin.'),
  'yichun/rice': ('Dataran Padi', 'Dataran subur Yuan-He telah lama dikenal sebagai lumbung padi bagi Provinsi Jiangxi.'),
  'zhangzhou/narcissus': ('Bunga Bakung', 'Bunga bakung paling terkenal di Tiongkok tumbuh di sini dan menjadi lambang perayaan musim semi.'),
  'zhangzhou/tulou': ('Tulou Hakka', 'Benteng raksasa berbentuk bulat dari tanah padat ini terdaftar di UNESCO dan mampu menampung satu desa dalam satu atap.'),
  'zhangzhou/banana': ('Buah Tropis', 'Kebun pisang, lengkeng, dan jeruk membuat delta yang hangat ini tetap hijau sepanjang tahun.'),
  'zhangzhou/coast': ('Pulau Dongshan', 'Dengan pantai berpasir emas dan desa nelayan, pulau ini menjadi permata di pesisir selatan.'),
  'guangzhou/tower': ('Canton Tower', 'Menara ramping yang dijuluki \'Pinggang Kecil\' ini merupakan salah satu menara tertinggi di dunia yang memukau dengan lampu warna-warni di malam hari.'),
  'guangzhou/dimsum': ('Yum Cha', 'Tradisi minum teh dan menyantap dim sum yang dikukus dalam keranjang bambu adalah jiwa dari kuliner Kanton.'),
  'guangzhou/academy': ('Akademi Klan Chen', 'Terkenal dengan ukiran kayu dan hiasan keramiknya, aula klan ini merupakan mahakarya kerajinan khas Kanton.'),
  'guangzhou/flower': ('Kota Bunga', 'Karena bunganya mekar sepanjang tahun, Guangzhou mengadakan pameran bunga besar-besaran setiap tahun baru dan dijuluki sebagai \'Kota Bunga\'.'),
  'wuhan/crane': ('Menara Bangau Kuning', 'Menghadap ke Sungai Yangtze, menara berusia ribuan tahun ini telah menginspirasi banyak puisi Tiongkok yang paling terkenal.'),
  'wuhan/noodle': ('Mi Kering Pedas', 'Mi kering dengan saus wijen merupakan menu sarapan yang wajib dicoba di Wuhan.'),
  'wuhan/duckneck': ('Leher Bebek Pedas', 'Leher bebek rebus yang pedas adalah camilan favorit warga kota untuk menemani obrolan larut malam.'),
  'wuhan/university': ('Bunga Sakura Kampus', 'Bunga sakura di Universitas Wuhan menarik ribuan pengunjung setiap musim semi.'),
  'tianjin/eye': ('Tianjin Eye', 'Kincir ria yang dibangun di atas jembatan ini menawarkan pemandangan kedua sisi sungai sekaligus.'),
  'tianjin/baozi': ('Bakpao Goubuli', 'Bakpao daging babi kukus dengan lipatan khas ini telah menjadi hidangan ikonik kota selama 150 tahun.'),
  'tianjin/crosstalk': ('Komedi Crosstalk', 'Komedi lisan dua orang yang disebut \'xiangsheng\' adalah tradisi Tianjin yang lahir di kedai-kedai teh.'),
  'tianjin/architecture': ('Kawasan Eropa', 'Vila-vila bergaya Eropa di Lima Jalan Utama membuat kota ini dijuluki sebagai \'museum arsitektur\'.'),
  'xiamen/island': ('Pulau Gulangyu', 'Jalanan bebas kendaraan dan vila-vila kolonial menjadikan pulau yang terdaftar di UNESCO ini sebagai museum terbuka.'),
  'xiamen/piano': ('Pulau Piano', 'Dengan jumlah piano per kapita terbanyak, Gulangyu dikenal sebagai \'pulau piano\'.'),
  'xiamen/egret': ('Bangau Putih', 'Bangau putih yang menjadi lambang kota ini mengingatkan pada nama lama Xiamen, yaitu \'pulau bangau\'.'),
  'xiamen/oyster': ('Omelet Tiram', 'Omelet renyah yang terbuat dari tiram segar dan telur merupakan hidangan andalan kuliner pesisir.'),
  'harbin/ice': ('Festival Es', 'Festival musim dingin yang menampilkan istana es raksasa berlampu ini merupakan yang terbesar di dunia.'),
  'harbin/cathedral': ('Katedral Santa Sofia', 'Katedral Ortodoks Rusia dengan kubah bawang ini merupakan lambang sejarah Eropa di kota Harbin.'),
  'harbin/sausage': ('Sosis Merah', 'Sosis merah asap bergaya Rusia ini merupakan kuliner khas kota yang telah ada selama seabad.'),
  'harbin/accordion': ('Kota Musik', 'Berkat warisan budaya Rusia yang kental, Harbin menjadi tempat berdirinya orkestra simfoni pertama di Tiongkok.'),
  'fuzhou/alley': ('Tiga Jalur dan Tujuh Gang', 'Kawasan kota tua dengan dinding putih dan atap hitam ini merupakan museum hidup arsitektur era Dinasti Ming dan Qing.'),
  'fuzhou/banyan': ('Kota Beringin', 'Pohon beringin raksasa yang berusia ratusan tahun menaungi jalanan kota, menjadikan Fuzhou dijuluki sebagai \'Kota Beringin\'.'),
  'fuzhou/hotspring': ('Pemandian Air Panas', 'Mata air panas yang muncul di pusat kota telah dimanfaatkan sebagai pemandian umum selama seribu tahun.'),
  'fuzhou/soup': ('Buddha Jumps Over the Wall', 'Sup mewah yang dimasak dari puluhan bahan pilihan ini merupakan mahakarya kuliner khas Fujian.'),
  'dongguan/robot': ('Pabrik Dunia', 'Dengan pabrik-pabrik yang terotomatisasi, Dongguan memproduksi sebagian besar kebutuhan elektronik dunia.'),
  'dongguan/basketball': ('Kota Bola Basket', 'Klub bola basket paling berprestasi di Tiongkok bermarkas di kota yang dijuluki sebagai \'Kota Bola Basket\' ini.'),
  'dongguan/keyuan': ('Taman Keyuan', 'Salah satu dari empat taman klasik paling terkenal di Guangdong yang dikagumi karena kolam dan paviliunnya yang indah.'),
  'dongguan/cannon': ('Benteng Humen', 'Benteng Humen merupakan lokasi dimulainya Perang Candu dan tempat bersejarah pembakaran candu.'),
  'lanzhou/beefnoodle': ('Mi Sapi Lanzhou', 'Dengan kaldu sapi bening dan mi tarik tangan, Lanzhou dikenal sebagai ibu kota mi di Tiongkok.'),
  'lanzhou/waterwheel': ('Kincir Air', 'Kincir air raksasa di tepi Sungai Kuning melambangkan teknik irigasi yang telah digunakan selama berabad-abad.'),
  'lanzhou/statue': ('Patung Ibu Sungai Kuning', 'Patung ibu dan anak di tepi sungai ini melambangkan sungai yang menjadi sumber kehidupan peradaban Tiongkok.'),
  'lanzhou/raft': ('Rakit Kulit Domba', 'Rakit tradisional yang terbuat dari kulit domba yang ditiup hingga mengembang ini masih digunakan untuk menyusuri Sungai Kuning.'),
  'urumqi/bazaar': ('Grand Bazaar', 'Dengan menara masjid dan kios rempah-rempah, pasar ini menghadirkan nuansa Jalur Sutra yang kental.'),
  'urumqi/tianshan': ('Danau Surgawi', 'Danau Surgawi yang terletak di bawah puncak bersalju Pegunungan Tianshan dikelilingi oleh hutan pohon cemara.'),
  'urumqi/kebab': ('Kebab Domba', 'Sate domba berbumbu yang dipanggang di atas bara api merupakan hidangan wajib bagi masyarakat Uighur.'),
  'urumqi/dance': ('Tari Uighur', 'Tarian Uighur yang berputar mengikuti irama drum dan rawap selalu memeriahkan setiap perayaan.'),
  'haikou/coconut': ('Kota Kelapa', 'Jalanan yang dipenuhi pohon kelapa memberikan julukan \'Kota Kelapa\' bagi Haikou.'),
  'haikou/arcade': ('Arcade Qilou', 'Bangunan \'qilou\' dengan pilar-pilar khas di bagian selatan membentuk lorong jalanan yang teduh.'),
  'haikou/crater': ('Kawah Vulkanik', 'Kawah gunung berapi yang sudah tidak aktif kini membentuk taman geologi hijau di pinggiran kota.'),
  'haikou/turtle': ('Laut Tropis', 'Perairan yang hangat, jernih, dan kaya akan terumbu karang menjadikan pesisir ini rumah bagi penyu laut.'),
  'luoyang/grotto': ('Gua Longmen', 'Puluhan ribu patung Buddha yang dipahat pada tebing batu merupakan harta karun seni warisan dunia UNESCO.'),
  'luoyang/peony': ('Ibu Kota Peony', 'Ribuan bunga peony yang mekar setiap bulan April menjadikan Luoyang dijuluki sebagai ibu kota bunga peony.'),
  'luoyang/whitehorse': ('Kuil Kuda Putih', 'Didirikan pada tahun 68 Masehi, kuil ini dianggap sebagai biara Buddha pertama di Tiongkok.'),
  'luoyang/capital': ('Ibu Kota Kuno', 'Sebagai ibu kota dari tiga belas dinasti, Luoyang merupakan salah satu pusat peradaban Tiongkok.'),
  'shantou/gongfutea': ('Teh Gongfu', 'Teh gongfu khas Chaoshan yang diseduh secara seremonial dalam cangkir kecil merupakan seni keramah-tamahan.'),
  'shantou/beefpot': ('Hotpot Daging Sapi', 'Hotpot khas Chaoshan yang menyajikan irisan daging sapi segar yang dimasak dalam hitungan detik sangatlah terkenal.'),
  'shantou/opera': ('Opera Teochew', 'Opera Teochew yang berusia 600 tahun dikenal karena nyanyiannya yang lembut dan kostumnya yang bersulam indah.'),
  'shantou/harbor': ('Pelabuhan Shantou', 'Sebagai kampung halaman banyak perantau Tionghoa, pelabuhan ini merupakan gerbang perdagangan maritim yang bersejarah.'),
  'baoding/mansion': ('Kediaman Gubernur', 'Kantor pemerintahan provinsi tertinggi dari era Dinasti Qing ini merupakan aula pemerintahan yang terpelihara dengan baik.'),
  'baoding/donkeyburger': ('Burger Keledai', 'Daging keledai berbumbu yang disajikan di dalam roti pipih renyah merupakan jajanan khas daerah ini.'),
  'baoding/balls': ('Bola Kesehatan', 'Tradisi memutar bola logam di telapak tangan untuk melatih otot tangan ini telah ada selama berabad-abad.'),
  'baoding/reeds': ('Rawa Baiyangdian', 'Lahan basah terbesar di wilayah utara ini merupakan surga bagi burung-burung di tengah hamparan alang-alang dan bunga teratai.'),
  'jilin/rime': ('Bunga Es', 'Lapisan es putih yang menyelimuti pepohonan di tepi Sungai Songhua merupakan salah satu dari empat keajaiban alam Tiongkok.'),
  'jilin/snowboard': ('Resor Ski', 'Dengan tumpukan salju yang tebal dan musim dingin yang panjang, kota ini menjadi salah satu destinasi ski terbaik di wilayah utara.'),
  'jilin/meteorite': ('Museum Meteorit', 'Meteorit berbatu terbesar di dunia yang jatuh pada tahun 1976 dipamerkan di museum ini.'),
  'jilin/skate': ('Sungai Songhua yang Membeku', 'Saat musim dingin, Sungai Songhua yang membeku berubah menjadi arena seluncur es yang ramai oleh warga.'),
  'ordos/khan': ('Mausoleum Genghis Khan', 'Mausoleum megah yang menghormati pahlawan padang rumput Genghis Khan ini merupakan pusat kebudayaan Mongol.'),
  'ordos/cashmere': ('Kasmir', 'Kain kasmir yang ditenun dari wol kambing Erdos telah membawa kota ini ke kancah industri tekstil dunia.'),
  'ordos/sanddune': ('Bukit Pasir Bernyanyi', 'Bukit pasir raksasa yang mengeluarkan suara saat disusuri ini menjadi destinasi favorit di Gurun Kubuqi.'),
  'ordos/yurt': ('Yurt Mongolia', 'Tenda kain putih yang didirikan di padang rumput luas ini melambangkan kehidupan masyarakat nomaden.'),
  'jining/confucius': ('Kuil Konfusius', 'Terletak di Qufu, kompleks kuil, kediaman, dan makam filsuf Konfusius ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'jining/barge': ('Kanal Besar', 'Sebagai pelabuhan sibuk di Kanal Beijing-Hangzhou, Jining dulunya merupakan pusat kebudayaan kanal yang penting.'),
  'jining/sword': ('Pahlawan Liangshan', 'Sebanyak 108 pahlawan dalam kisah klasik \'Batas Air\' berkumpul di perbukitan rawa ini.'),
  'jining/fishnet': ('Danau Weishan', 'Di danau teratai terbesar di utara ini, para nelayan masih menebar jala dengan cara tradisional.'),
  'langfang/culture': ('Pusat Budaya Jalur Sutra', 'Pusat kebudayaan modern yang megah ini mengumpulkan berbagai seni dari Jalur Sutra di bawah satu atap.'),
  'langfang/furniture': ('Kota Furnitur', 'Xianghe yang berada di dekatnya merupakan salah satu pusat pembuatan dan perdagangan furnitur terbesar di Tiongkok.'),
  'langfang/tunnel': ('Terowongan Perang Kuno', 'Terowongan militer berusia ribuan tahun yang digali di bawah tanah ini menjadi saksi bisu pertahanan perbatasan masa lalu.'),
  'langfang/themepark': ('Taman \'Kota No. 1\'', 'Taman hiburan luas yang merekonstruksi kota bertembok kuno ini menjadi destinasi wisata keluarga yang populer.'),
  'yancheng/salt': ('Kota Garam', 'Namanya berarti \'benteng garam\', karena selama berabad-abad Yancheng menjadi pusat produksi garam di Tiongkok.'),
  'yancheng/crane': ('Bangau Mahkota Merah', 'Lahan basah pesisir ini merupakan tempat musim dingin terbesar di dunia bagi burung bangau mahkota merah liar.'),
  'yancheng/elk': ('Rusa Père David', 'Sempat punah di alam liar, rusa milu kini telah berhasil dikembangbiakkan kembali di kawasan lahan basah ini.'),
  'yancheng/wetland': ('Lahan Basah Pesisir', 'Dataran pasang surut yang terdaftar dalam situs warisan UNESCO ini menjadi persinggahan global bagi burung migran.'),
  'huzhou/brush': ('Kuas Hu', 'Kuas Hu, yang merupakan salah satu dari \'empat harta\' kaligrafi Tiongkok, diproduksi di kota ini.'),
  'huzhou/bamboo': ('Hutan Bambu Anji', 'Hutan bambu hijau yang membentang luas ini pernah menjadi inspirasi film dan memberikan kesejukan udara di sekitarnya.'),
  'huzhou/silkworm': ('Ulat Sutra', 'Pesisir selatan Danau Tai telah menjadi pusat produksi sutra murbei selama ribuan tahun.'),
  'huzhou/whitetea': ('Teh Putih Anji', 'Dengan daun berwarna pucat dan rasa yang manis, teh putih Anji termasuk salah satu teh paling langka di Tiongkok.'),
  'quzhou/go': ('Go (Weiqi)', 'Dikenal melalui legenda Gunung Lanke, kota ini dihormati sebagai tanah kelahiran permainan Go.'),
  'quzhou/peaks': ('Gunung Jianglang', 'Tiga pilar batu raksasa yang menjulang ke langit membentuk lanskap unik warisan UNESCO.'),
  'quzhou/ponkan': ('Jeruk Ponkan Quzhou', 'Jeruk ponkan berkulit manis ini merupakan buah khas musim dingin dari perbukitan yang sejuk.'),
  'quzhou/cake': ('Roti Pipih Panggang', 'Roti pipih wijen renyah yang dipanggang di dinding oven merupakan menu sarapan klasik setempat.'),
  'huainan/tofu': ('Tempat Kelahiran Tahu', 'Ditemukan di Gunung Bagong 2.000 tahun lalu, tahu menyebar ke seluruh dunia dari tempat ini.'),
  'huainan/coalmine': ('Kota Batu Bara', 'Kaya akan lapisan batu bara, Huainan menjadi basis energi utama di Tiongkok bagian timur.'),
  'huainan/oldtown': ('Kota Tua Shou', 'Tembok kota era Dinasti Song yang terpelihara utuh merupakan contoh langka desain pertahanan kuno.'),
  'huainan/classic': ('Huainanzi', 'Karya klasik filsafat yang disusun oleh Pangeran Liu An ini ditulis di tanah ini.'),
  'jingdezhen/porcelain': ('Ibu Kota Porselen', 'Memproduksi porselen kekaisaran selama seribu tahun, kota ini dikenal sebagai ibu kota porselen dunia.'),
  'jingdezhen/kiln': ('Tungku Kuno', 'Tungku berbentuk naga berbahan bakar kayu menjaga seni tradisional pembakaran porselen tetap hidup.'),
  'jingdezhen/bluewhite': ('Porselen Biru-Putih', 'Porselen putih dengan motif biru kobalt adalah ciri khas kota ini yang mendunia.'),
  'jingdezhen/painting': ('Lukisan Porselen', 'Porselen yang dilukis dengan kuas halus oleh para seniman ahli sangat dihargai layaknya karya seni lukis.'),
  'jian/jinggang': ('Pegunungan Jinggang', 'Pegunungan berkabut yang menjadi basis revolusi pertama ini adalah pusat wisata sejarah merah.'),
  'jian/torch': ('Percikan Revolusi', 'Tanah yang melahirkan semboyan \'satu percikan api dapat membakar padang rumput\' ini merupakan situs peringatan bersejarah.'),
  'jian/academy': ('Akademi Bailuzhou', 'Akademi berusia seribu tahun di pulau Sungai Gan ini telah mendidik banyak cendekiawan kekaisaran.'),
  'jian/pine': ('Pinus Jinggang', 'Pohon pinus merah yang menembus kabut melambangkan semangat pegunungan dan ketangguhan.'),
  'nanping/wuyi': ('Pegunungan Wuyi', 'Pegunungan yang terdaftar dalam situs warisan dunia UNESCO ini merupakan harta karun alam dan budaya dengan tebing merah serta ngarai yang hijau.'),
  'nanping/rocktea': ('Teh Batu', 'Teh oolong \'Big Red Robe\' yang tumbuh di tebing ini termasuk salah satu teh termahal di dunia.'),
  'nanping/bambooraft': ('Rakit Sembilan Kelokan', 'Wisatawan dapat menyusuri Sungai Sembilan Kelokan di atas rakit bambu yang meluncur di antara tebing-tebing merah.'),
  'nanping/scholar': ('Zhu Xi', 'Zhu Xi, tokoh pendiri Neo-Konfusianisme, pernah mengajar di kaki pegunungan ini.'),
  'shenzhen/skyscraper': ('Pencakar Langit', 'Hutan gedung pencakar langit yang tumbuh dari desa nelayan dalam 40 tahun ini merupakan keajaiban reformasi Tiongkok.'),
  'shenzhen/chip': ('Kota Teknologi', 'Dengan pasar elektronik Huaqiangbei dan berbagai raksasa teknologi, Shenzhen dijuluki sebagai \'Lembah Silikon Tiongkok\'.'),
  'shenzhen/miniature': ('Window of the World', 'Taman hiburan yang menampilkan miniatur berbagai landmark terkenal dunia ini merupakan ikon kota Shenzhen.'),
  'shenzhen/mangrove': ('Teluk Shenzhen', 'Teluk yang dikelilingi hutan bakau ini menjadi tempat perlindungan bagi burung migran dan burung kuntul.'),
  'xian/terracotta': ('Prajurit Terakota', 'Ribuan patung tanah liat yang menjaga makam Kaisar Qin ini dikenal sebagai keajaiban dunia kedelapan.'),
  'xian/citywall': ('Tembok Kota Xi\'an', 'Tembok kota dari era Dinasti Ming yang paling terawat di Tiongkok ini dapat dijelajahi dengan bersepeda di sepanjang bentengnya.'),
  'xian/drumtower': ('Menara Lonceng', 'Menara lonceng dari era Dinasti Ming yang terletak tepat di pusat kota ini menandai jantung ibu kota kuno tersebut.'),
  'xian/roujiamo': ('Roujiamo', 'Daging berbumbu yang disajikan dalam roti pipih renyah, roujiamo sering disebut sebagai burger asli dari Jalur Sutra.'),
  'suzhou/garden': ('Taman Klasik Suzhou', 'Taman-taman yang dirancang dengan indah menggunakan bebatuan, kolam, dan paviliun ini telah diakui oleh UNESCO.'),
  'suzhou/watertown': ('Kota Air', 'Dengan kanal, jembatan batu, dan rumah-rumah putihnya, Suzhou dijuluki sebagai \'Venesia dari Timur\'.'),
  'suzhou/embroidery': ('Sulam Su', 'Sulam sutra dua sisi merupakan kerajinan tangan khas Suzhou yang telah berusia ribuan tahun.'),
  'suzhou/kunqu': ('Opera Kunqu', 'Opera Kunqu yang elegan, yang dianggap sebagai induk dari seluruh opera Tiongkok, lahir di kota ini.'),
  'kunming/stoneforest': ('Hutan Batu', 'Pilar-pilar batu kapur raksasa yang terbentuk selama jutaan tahun menciptakan labirin batu yang menakjubkan.'),
  'kunming/springcity': ('Kota Musim Semi', 'Dengan iklim yang sejuk sepanjang tahun, Kunming dijuluki sebagai \'kota musim semi\' tempat bunga-bunga selalu bermekaran.'),
  'kunming/seagull': ('Burung Camar Kepala Hitam', 'Setiap musim dingin, ribuan burung camar dari Siberia datang dan memutihkan tepian danau.'),
  'kunming/ricenoodle': ('Mi Jembatan Penyeberangan', 'Mi beras tipis yang dimasukkan ke dalam kaldu panas di meja makan merupakan hidangan khas Yunnan.'),
  'jinan/spring': ('Kota Mata Air', 'Tujuh puluh dua mata air terkenal yang menyembur dari tanah memberikan Jinan julukan \'kota mata air\'.'),
  'jinan/daminglake': ('Danau Daming', 'Dikelilingi oleh pohon dedalu dan bunga teratai, danau kota ini dialiri oleh air dari mata air setempat.'),
  'jinan/buddhamountain': ('Gunung Seribu Buddha', 'Dengan ratusan patung Buddha yang dipahat di lerengnya, gunung ini menjadi tempat ziarah yang penting.'),
  'jinan/poet': ('Penyair Li Qingzhao', 'Penyair wanita terhebat di Tiongkok, Li Qingzhao, lahir di kota mata air ini.'),
  'ningbo/library': ('Paviliun Tianyi', 'Paviliun Tianyi yang berusia 450 tahun merupakan perpustakaan pribadi tertua yang masih ada di Asia.'),
  'ningbo/port': ('Pelabuhan Kargo', 'Ningbo-Zhoushan merupakan pelabuhan tersibuk di dunia berdasarkan tonase kargo.'),
  'ningbo/tangyuan': ('Tangyuan', 'Bola ketan berisi wijen yang disebut \'tangyuan\' adalah hidangan manis khas kota ini.'),
  'ningbo/seafood': ('Hidangan Laut', 'Ikan croaker kuning dan kepiting dari Laut Tiongkok Timur menjadi bahan utama dalam santapan lokal.'),
  'shijiazhuang/bridge': ('Jembatan Zhaozhou', 'Jembatan lengkung batu berusia 1.400 tahun ini merupakan jembatan lengkung terbuka tertua di dunia.'),
  'shijiazhuang/clifftemple': ('Gunung Cangyan', 'Jembatan kuil yang tergantung di antara tebing ini telah menjadi latar belakang bagi banyak film.'),
  'shijiazhuang/redbase': ('Basis Xibaipo', 'Desa tempat perencanaan Tiongkok Baru ini merupakan destinasi sakral dalam wisata sejarah revolusioner.'),
  'shijiazhuang/pharma': ('Kota Farmasi', 'Sebagai salah satu produsen obat terbesar di Tiongkok, kota ini menjadi pusat produksi antibiotik.'),
  'taiyuan/jincitemple': ('Kuil Jinci', 'Dengan patung dan mata air berusia tiga ribu tahun, Jinci adalah taman kuil paling anggun di Tiongkok utara.'),
  'taiyuan/coalcart': ('Negeri Batu Bara', 'Cadangan batu bara Shanxi menjadi sumber energi utama Tiongkok, dan Taiyuan adalah ibu kota dari kekayaan tersebut.'),
  'taiyuan/vinegar': ('Cuka Hitam', 'Cuka hitam yang telah difermentasi lama merupakan elemen rasa asam yang esensial dalam kuliner Shanxi.'),
  'taiyuan/twinpagoda': ('Pagoda Kembar', 'Dua pagoda berbentuk oktagonal dari zaman Dinasti Ming ini berdiri berdampingan sebagai ikon kota.'),
  'hohhot/lamatemple': ('Kuil Dazhao', 'Terkenal dengan patung Buddha peraknya, biara Buddha Tibet ini merupakan pusat spiritual kota Hohhot.'),
  'hohhot/dairy': ('Ibu Kota Susu', 'Merek-merek susu terbesar di Tiongkok lahir di sini, sehingga kota ini dijuluki sebagai ibu kota susu.'),
  'hohhot/wrestling': ('Gulat Mongolia', 'Gulat Bökh, yang menjadi puncak festival Naadam, merupakan ajang unjuk kekuatan khas masyarakat padang rumput.'),
  'hohhot/prairie': ('Padang Rumput', 'Di luar kota terbentang padang rumput Mongolia yang hijau, lengkap dengan kuda dan kawanan ternak.'),
  'sanya/resortbeach': ('Pantai Tropis', 'Pasir putih halus dan air laut biru kehijauan di Teluk Yalong menjadikannya sebagai Hawaii-nya Tiongkok.'),
  'sanya/guanyin': ('Patung Guanyin', 'Menjulang setinggi 108 meter di atas laut, patung Guanyin ini merupakan salah satu figur dewi tertinggi di dunia.'),
  'sanya/diving': ('Menyelam', 'Dengan air yang hangat, jernih, dan terumbu karang yang indah, Sanya adalah surga menyelam di Tiongkok.'),
  'sanya/coconutdrink': ('Kelapa', 'Air kelapa segar dari perkebunan tropis adalah minuman penyegar yang paling dicari di pulau ini.'),
  'yangzhou/slenderlake': ('Danau Slender West', 'Dengan pemandangan pohon dedalu dan jembatan putih, danau yang ramping ini tampak seanggun lukisan.'),
  'yangzhou/friedrice': ('Nasi goreng Yangzhou', 'Nasi goreng emas yang dipadukan dengan udang dan telur ini merupakan hidangan klasik yang mendunia.'),
  'yangzhou/morningtea': ('Teh pagi', 'Menikmati sarapan elegan berupa bakpao dan teh merupakan ritual khas masyarakat Yangzhou.'),
  'yangzhou/gegarden': ('Taman Ge', 'Taman bambu yang merepresentasikan empat musim melalui susunan batu ini adalah mahakarya desain klasik.'),
  'weihai/navalisland': ('Pulau Liugong', 'Sebagai pangkalan Armada Beiyang, pulau ini menjadi saksi bisu sejarah angkatan laut Tiongkok modern.'),
  'weihai/swan': ('Danau Angsa', 'Setiap musim dingin, ratusan angsa whooper dari Siberia datang bermigrasi ke laguna pesisir ini.'),
  'weihai/seacucumber': ('Teripang', 'Dibudidayakan di perairan yang dingin dan bersih, teripang menjadi hidangan laut paling berharga di kota ini.'),
  'weihai/cape': ('Tanjung Tiongkok', 'Tanjung paling timur di Tiongkok ini merupakan tempat pertama matahari menyapa daratan negara tersebut.'),
  'handan/taichi': ('Tai Chi', 'Kota Guangfu, tempat lahirnya aliran Yang dan Wu, dikenal sebagai pusat seni bela diri taijiquan.'),
  'handan/congtai': ('Teras Congtai', 'Teras tanah dari masa Kerajaan Zhao kuno ini telah menyaksikan sejarah selama lebih dari 2.000 tahun.'),
  'handan/idiom': ('Kota Idiom', 'Lebih dari 1.500 idiom Tiongkok lahir di sini, menjadikan Handan dijuluki sebagai \'kota idiom\'.'),
  'handan/ciporcelain': ('Keramik Cizhou', 'Keramik Cizhou dengan motif hitam di atas putih merupakan karya klasik dari seni keramik rakyat.'),
  'daqing/oilpump': ('Ladang minyak', 'Ladang minyak terbesar di Tiongkok ini dipenuhi dengan mesin pompa minyak yang bergerak naik-turun.'),
  'daqing/oilworker': ('Manusia Besi', 'Kegigihan pahlawan pekerja minyak Wang Jinxi menjadi semangat pendiri kota ini.'),
  'daqing/reedlake': ('Lahan basah', 'Danau luas yang ditumbuhi alang-alang di antara sumur minyak menjadi habitat bagi burung bangau dan angsa.'),
  'daqing/hotspring': ('Pemandian air panas', 'Air mineral panas dari bawah tanah menawarkan relaksasi yang menenangkan di tengah dinginnya wilayah utara.'),
  'zibo/bbq': ('Sate Zibo', 'Sate yang dipanggang di atas anglo kecil dan dibungkus dengan panekuk tipis ini menjadi tren kuliner yang populer di seluruh Tiongkok.'),
  'zibo/cuju': ('Cuju', 'Cuju merupakan bentuk sepak bola tertua di dunia yang dimainkan di ibu kota kuno Qi, Linzi.'),
  'zibo/ceramic': ('Keramik Zibo', 'Dengan tradisi tungku pembakaran berusia ribuan tahun, kota ini menjadi pusat keramik utama di Tiongkok utara.'),
  'zibo/glass': ('Liuli', 'Liuli adalah kerajinan kaca berwarna buatan tangan yang memancarkan keindahan saat terkena cahaya.'),
  'taian/mounttai': ('Gunung Tai', 'Sebagai yang utama dari Lima Gunung Suci, Gunung Tai adalah puncak paling sakral tempat para kaisar memberikan persembahan kepada langit.'),
  'taian/sunrise': ('Matahari Terbit di Puncak', 'Menyaksikan matahari terbit di atas lautan awan adalah hadiah utama bagi mereka yang mendaki Gunung Tai.'),
  'taian/stonesteps': ('Tangga Batu', 'Sebanyak 7.000 anak tangga batu menuju puncak menjadi ujian fisik bagi para peziarah.'),
  'taian/daitemple': ('Kuil Dai', 'Kuil megah di kaki gunung ini merupakan tempat para kaisar mempersiapkan diri sebelum melakukan ritual di Gunung Tai.'),
  'lianyungang/monkey': ('Gunung Huaguo', 'Gunung Huaguo, yang dikenal sebagai rumah Raja Kera dalam kisah \'Perjalanan ke Barat\', terletak di sini.'),
  'lianyungang/seaport': ('Pelabuhan Lianyungang', 'Sebagai gerbang laut timur Jalur Sutra, pelabuhan ini merupakan ujung Pasifik dari jembatan kereta api Eurasia.'),
  'lianyungang/mountain': ('Gunung Yuntai', 'Dengan puncak yang curam dan hutan yang lebat, Yuntai adalah gunung tertinggi di Provinsi Jiangsu.'),
  'lianyungang/crystal': ('Sentra Kristal', 'Wilayah Donghai di dekatnya merupakan salah satu pasar kristal kuarsa terbesar di dunia.'),
  'maanshan/libai': ('Penyair Li Bai', 'Kota tepi sungai ini menjadi tempat peristirahatan terakhir sekaligus lokasi makam penyair terbesar Tiongkok, Li Bai.'),
  'maanshan/steel': ('Kota Baja', 'Pabrik baja Magang menjadikan kota ini sebagai salah satu basis industri besi dan baja utama di Tiongkok.'),
  'maanshan/rivercliff': ('Tebing Caishiji', 'Tebing yang menjorok ke Sungai Yangtze ini merupakan latar puitis dari legenda penyair Li Bai.'),
  'maanshan/moonwine': ('Bulan dan Anggur', 'Puisi Li Bai tentang bulan dan anggur masih dirayakan dalam festival-festival di tepi sungai.'),
  'longyan/tulou': ('Rumah Tanah Yongding', 'Benteng hunian berbentuk bulat raksasa milik masyarakat Hakka yang tersebar di perbukitan ini telah terdaftar sebagai Situs Warisan Dunia UNESCO.'),
  'longyan/redmeeting': ('Pertemuan Gutian', 'Pertemuan bersejarah yang menentukan arah Tentara Merah ini diselenggarakan di desa tersebut.'),
  'longyan/hakka': ('Budaya Hakka', 'Masyarakat Hakka, yang merupakan perantau dari utara, tetap melestarikan bahasa dan kuliner mereka di perbukitan ini.'),
  'longyan/mountain': ('Gunung Guanzhi', 'Dengan tebing merah dan kolam yang jernih, gunung ini merupakan permata alam di Fujian bagian selatan.'),
  'beijing/great-wall': ('Tembok Besar Tiongkok', 'Benteng terpanjang di dunia ini dibangun selama berabad-abad untuk menjaga perbatasan utara Tiongkok, dengan bagian Badaling di dekat Beijing sebagai area yang paling sering dikunjungi.'),
  'beijing/temple': ('Kuil Surga', 'Kompleks suci tempat kaisar dari Dinasti Ming dan Qing berdoa demi panen yang melimpah, yang dikenal dengan atap biru bertingkat tiga tanpa paku.'),
  'beijing/pagoda': ('Pagoda Tianning', 'Pagoda bata setinggi 57 meter dari Dinasti Liao ini merupakan salah satu bangunan tertua di Beijing yang masih berdiri sebagai saksi sejarah kota selama seribu tahun.'),
  'beijing/opera': ('Opera Beijing', 'Seni teater tradisional Tiongkok berusia 200 tahun yang memadukan nyanyian, dialog, seni bela diri, dan akrobat dengan riasan wajah khas untuk menggambarkan karakter tokoh.'),
};
